export { expect } from '@playwright/test';

import { Page, Locator } from '@playwright/test';

export class AuthPage {
  readonly page: Page;
  readonly emailInput: Locator;
  readonly passwordInput: Locator;
  readonly loginSubmitButton: Locator;
  readonly loginError: Locator;
  readonly emailError: Locator;
  readonly passwordError: Locator;
  readonly pageHeading: Locator;
  readonly pageSubheading: Locator;
  readonly signUpLink: Locator;

  constructor(page: Page) {
    this.page = page;
    this.emailInput = page.getByTestId('email-input');
    this.passwordInput = page.getByTestId('password-input');
    this.loginSubmitButton = page.getByTestId('login-submit');
    this.loginError = page.getByTestId('login-error');
    this.emailError = page.getByTestId('email-error');
    this.passwordError = page.getByTestId('password-error');
    this.pageHeading = page.getByRole('heading', { name: 'CareSync' });
    this.pageSubheading = page.getByText('Sign in to your account');
    this.signUpLink = page.getByRole('link', { name: 'Sign up' });
  }

  async goto() {
    await this.page.goto('/login');
  }

  async login(email: string, password: string) {
    await this.emailInput.fill(email);
    await this.passwordInput.fill(password);
    await this.loginSubmitButton.click();
  }

  async getLoginError() {
    return this.loginError;
  }

  async getEmailError() {
    return this.emailError;
  }

  async getPasswordError() {
    return this.passwordError;
  }

  async getUserNameFromSidebar() {
    return this.page.locator('[class*="user-name"], [data-testid*="user"]').first();
  }

  async getUserRoleFromSidebar() {
    return this.page.locator('[class*="role"]').first();
  }

  async clickLogout() {
    await this.page.getByRole('button', { name: 'Log out' }).click();
  }
}

