import { Page, Locator, expect } from '@playwright/test';

export class AuthPage {
  readonly page: Page;

  // Login form elements
  readonly emailInput: Locator;
  readonly passwordInput: Locator;
  readonly signInButton: Locator;
  readonly registerLink: Locator;

  // Error messages
  readonly emailError: Locator;
  readonly passwordError: Locator;
  readonly loginError: Locator;

  // Dashboard elements (used after login)
  readonly welcomeHeading: Locator;
  readonly userNameInSidebar: Locator;
  readonly userRoleInSidebar: Locator;
  readonly logoutButton: Locator;

  constructor(page: Page) {
    this.page = page;

    // Login form elements
    this.emailInput = page.getByTestId('email-input');
    this.passwordInput = page.getByTestId('password-input');
    this.signInButton = page.getByTestId('login-submit');
    this.registerLink = page.getByTestId('register-link');

    // Error messages
    this.emailError = page.getByTestId('email-error');
    this.passwordError = page.getByTestId('password-error');
    this.loginError = page.getByTestId('login-error');

    // Dashboard elements
    this.welcomeHeading = page.getByRole('heading', { name: /Welcome back, .*/ });
    this.userNameInSidebar = page.getByRole('complementary').getByText(/.* Doe/);
    this.userRoleInSidebar = page.getByRole('complementary').getByText(/patient|doctor|admin/);
    this.logoutButton = page.getByRole('button', { name: 'Log out' });
  }

  async goto() {
    await this.page.goto('/login');
  }

  async login(email: string, password: string) {
    await this.emailInput.fill(email);
    await this.passwordInput.fill(password);
    await this.signInButton.click();
  }

  async expectLoginError() {
    await expect(this.loginError).toBeVisible();
  }

  async expectEmailError() {
    await expect(this.emailError).toBeVisible();
  }

  async expectPasswordError() {
    await expect(this.passwordError).toBeVisible();
  }

  async expectOnLoginPage() {
    await expect(this.page).toHaveURL(/\/login$/);
    await expect(this.emailInput).toBeVisible();
    await expect(this.passwordInput).toBeVisible();
    await expect(this.signInButton).toBeVisible();
  }

  async expectOnDashboard() {
    await expect(this.page).toHaveURL(/\/dashboard$/);
    await expect(this.welcomeHeading).toBeVisible();
  }

  async logout() {
    await this.logoutButton.click();
  }

  async expectEmailRetained(email: string) {
    await expect(this.emailInput).toHaveValue(email);
  }
}

import { test, expect } from '../../../fixtures';
import { AuthPage } from '../../../pages/auth/AuthPage';

test.describe('@smoke @auth Authentication Flow', () => {
  let authPage: AuthPage;

  test.beforeEach(async ({ page }) => {
    authPage = new AuthPage(page);
  });

  test.describe('Login - Valid Credentials', () => {
    test('patient should be redirected to /dashboard after login', async ({ page }) => {
      await authPage.goto();
      await authPage.login('jane.doe@caresync.dev', 'Password123!');

      await expect(page).toHaveURL(/\/dashboard/);
    });

    test('admin should be redirected to /admin after login', async ({ page }) => {
      await authPage.goto();
      await authPage.login('admin@caresync.dev', 'Admin123!');

      await expect(page).toHaveURL(/\/admin/);
    });

    test('doctor should be redirected to /doctor after login', async ({ page }) => {
      await authPage.goto();
      await authPage.login('john.smith@caresync.dev', 'Doctor123!');

      await expect(page).toHaveURL(/\/doctor/);
    });

    test('dashboard shows welcome message with user first name', async ({ page }) => {
      await authPage.goto();
      await authPage.login('jane.doe@caresync.dev', 'Password123!');

      const welcomeMessage = page.locator('h1');
      await expect(welcomeMessage).toContainText('Welcome back, Jane!');
    });

    test('sidebar shows user full name and role', async ({ page }) => {
      await authPage.goto();
      await authPage.login('jane.doe@caresync.dev', 'Password123!');

      const userInfo = page.locator('[class*="user"]').first();
      await expect(userInfo).toContainText('Jane Doe');
      await expect(userInfo).toContainText('patient');
    });
  });

  test.describe('Login - Invalid Credentials', () => {
    test('shows error message for wrong password', async ({ page }) => {
      await authPage.goto();
      await authPage.login('jane.doe@caresync.dev', 'wrongpassword');

      await expect(page).toHaveURL(/\/login/);
      await expect(authPage.loginError).toBeVisible();
      await expect(authPage.loginError).toContainText(/invalid email or password/i);
    });

    test('shows error message for non-existent email', async ({ page }) => {
      await authPage.goto();
      await authPage.login('nonexistent@test.com', 'anypassword');

      await expect(page).toHaveURL(/\/login/);
      await expect(authPage.loginError).toBeVisible();
      await expect(authPage.loginError).toContainText(/invalid email or password/i);
    });

    test('email field retains value after failed attempt', async ({ page }) => {
      await authPage.goto();
      const testEmail = 'jane.doe@caresync.dev';
      await authPage.login(testEmail, 'wrongpassword');

      await expect(page).toHaveURL(/\/login/);
      await expect(authPage.emailInput).toHaveValue(testEmail);
    });
  });

  test.describe('Login - Empty Fields Validation', () => {
    test('shows validation errors for both empty fields', async ({ page }) => {
      await authPage.goto();
      await authPage.emailInput.fill('');
      await authPage.passwordInput.fill('');
      await authPage.loginSubmitButton.click();

      await expect(authPage.emailError).toBeVisible();
      await expect(authPage.emailError).toContainText(/invalid email address/i);
    });

    test('shows password validation error when only email is filled', async ({ page }) => {
      await authPage.goto();
      await authPage.emailInput.fill('test@example.com');
      await authPage.passwordInput.fill('');
      await authPage.loginSubmitButton.click();

      await expect(authPage.passwordError).toBeVisible();
      await expect(authPage.passwordError).toContainText(/password must be at least/i);
    });

    test('shows email validation error when only password is filled', async ({ page }) => {
      await authPage.goto();
      await authPage.emailInput.fill('');
      await authPage.passwordInput.fill('password123');
      await authPage.loginSubmitButton.click();

      await expect(authPage.emailError).toBeVisible();
      await expect(authPage.emailError).toContainText(/invalid email address/i);
    });
  });

  test.describe('Logout', () => {
    test('authenticated user is redirected to /login after logout', async ({ page }) => {
      await authPage.goto();
      await authPage.login('jane.doe@caresync.dev', 'Password123!');

      await expect(page).toHaveURL(/\/dashboard/);
      await authPage.logoutButton.click();

      await expect(page).toHaveURL(/\/login/);
      await expect(authPage.pageHeading).toBeVisible();
    });

    test('navigating to /dashboard while logged out redirects to /login', async ({ page }) => {
      await page.goto('/dashboard');

      await expect(page).toHaveURL(/\/login/);
    });
  });
});

